// ⚠️ CRITICAL: Webhook data is under .body — NOT directly on .json
// This is the #1 n8n Code Node mistake. See: n8n-code-javascript skill.
const input = $input.first().json.body;

if (!input) {
  throw new Error('Empty webhook payload — no body received');
}

// Required fields
const { flowchart_id, source_id, notebook_id, source_text, source_title } = input;

if (!flowchart_id || !source_id || !source_text) {
  throw new Error('Missing required fields: flowchart_id, source_id, source_text');
}

// Validate UUID format (basic check)
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(flowchart_id)) {
  throw new Error(`Invalid flowchart_id UUID: ${flowchart_id}`);
}

// Validate source_text length
const MAX_TEXT_LENGTH = 100000; // ~100K chars
const truncatedText = source_text.length > MAX_TEXT_LENGTH
  ? source_text.substring(0, MAX_TEXT_LENGTH) + '\n\n[...văn bản đã được cắt ngắn...]'
  : source_text;

// Return format: MUST be [{json: {...}}] — n8n Code Node requirement
return [{
  json: {
    flowchart_id,
    source_id,
    notebook_id,
    source_text: truncatedText,
    source_title: source_title || 'Untitled',
  }
}];

const aiOutput = $input.first().json;
const flowchartId = $('Validate Input').first().json.flowchart_id;

// The OpenAI node returns the response in different fields depending on version
// Try content field first, then text, then message
let rawText = aiOutput.message?.content || aiOutput.text || aiOutput.content || '';

// Strip markdown code fences if AI wrapped them
rawText = rawText.replace(/^```json?\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error(`AI returned invalid JSON: ${e.message}. Raw: ${rawText.substring(0, 200)}`);
}

// Validate required fields
if (!parsed.mermaid_code || typeof parsed.mermaid_code !== 'string') {
  throw new Error('AI response missing mermaid_code field');
}
if (!parsed.title || !parsed.summary) {
  throw new Error('AI response missing title or summary field');
}

return [{
  json: {
    flowchart_id: flowchartId,
    mermaid_code: parsed.mermaid_code,
    title: parsed.title,
    summary: parsed.summary,
  }
}];

const { flowchart_id, mermaid_code, title, summary } = $input.first().json;

// 1. Must start with flowchart direction
if (!/^flowchart\s+(TD|TB|BT|RL|LR)/i.test(mermaid_code.trim())) {
  throw new Error('Invalid Mermaid: must start with "flowchart TD" (or TB/BT/RL/LR)');
}

// 2. XSS/injection prevention
const xssPatterns = [
  /<script/i,
  /javascript:/i,
  /on\w+\s*=/i,
  /<iframe/i,
  /<object/i,
  /<embed/i,
  /data:text\/html/i,
];
for (const pattern of xssPatterns) {
  if (pattern.test(mermaid_code)) {
    throw new Error(`Security: injection pattern detected in Mermaid code: ${pattern}`);
  }
}

// 3. Count nodes (lines with node definitions: ID[...], ID{...}, ID([...]), ID[/...\])
const nodePattern = /^\s*[A-Za-z0-9_]+\s*[\[\({]/gm;
const nodeMatches = mermaid_code.match(nodePattern) || [];
// Deduplicate node IDs (same node can appear in edge definitions)
const nodeIds = new Set();
const idExtract = /^\s*([A-Za-z0-9_]+)/;
for (const match of nodeMatches) {
  const id = match.match(idExtract)?.[1];
  if (id) nodeIds.add(id);
}

if (nodeIds.size > 20) {
  throw new Error(`Node count ${nodeIds.size} exceeds maximum of 20. Reduce complexity.`);
}

if (nodeIds.size === 0) {
  throw new Error('No nodes detected in Mermaid code');
}

// 4. Sanitize: remove any null bytes or control chars (keep newlines/tabs)
const sanitized = mermaid_code.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');

return [{
  json: {
    flowchart_id,
    mermaid_code: sanitized,
    title: title.substring(0, 200),     // Cap title length
    summary: summary.substring(0, 2000), // Cap summary length
    node_count: nodeIds.size,
  }
}];

// Error Trigger provides error details in $input.first().json
const error = $input.first().json;

// Get flowchart_id from the workflow execution context
// Try nodes in order of reliability
let flowchartId = null;
try {
  flowchartId = $('Validate Input').first().json.flowchart_id;
} catch (e) {
  // If Validate Input itself failed, try webhook body
  // ⚠️ CRITICAL: Webhook data is under .body (n8n-code-javascript skill)
  try {
    flowchartId = $('Webhook').first().json.body?.flowchart_id;
  } catch (e2) {
    // Cannot determine flowchart_id — return error info without DB update
    return [{ json: { error: 'Cannot determine flowchart_id', original_error: error.message } }];
  }
}

// Guard: if flowchartId is still null, we can't update DB
if (!flowchartId) {
  return [{ json: { error: 'flowchart_id is null', original_error: error.message } }];
}

const errorMessage = error.message || error.description || 'Unknown workflow error';

// Return format: [{json: {...}}] — n8n Code Node requirement
return [{
  json: {
    flowchart_id: flowchartId,
    error_message: errorMessage.substring(0, 1000),
  }
}];
